 407→    fn handle_generate(&mut self, mut resp: Response, req: &Request) -> Response {
 408→        let file_path = match &req.file {
 409→            Some(f) => f,
 410→            None => {
 411→                resp.status = "error".to_string();
 412→                resp.code = Some("invalid_request".to_string());
 413→                resp.message = Some("generate command requires a file path".to_string());
 414→                return resp;
 415→            }
 416→        };
 417→        let func_name = match &req.name {
 418→            Some(n) => n.clone(),
 419→            None => {
 420→                resp.status = "error".to_string();
 421→                resp.code = Some("invalid_request".to_string());
 422→                resp.message = Some("generate command requires a name".to_string());
 423→                return resp;
 424→            }
 425→        };
