 427→        let path = std::path::Path::new(file_path);
 428→        let ext = path.extension().and_then(|e| e.to_str());
 429→
 430→        match ext {
 431→            Some("wasm") => {
 432→                match self.wasm_cache.generate(path, &func_name, req.recipe.as_ref()) {
 433→                    Ok((value, generator_id, recipe)) => {
 434→                        resp.status = "generate".to_string();
 435→                        resp.value = Some(value);
 436→                        resp.generator_id = Some(generator_id);
 437→                        resp.recipe = recipe;
