 446→                }
 447→            }
 448→            Some("rs") => {
 449→                if let Some(ref registry) = self.native_registry {
 450→                    match registry.generate(&func_name, req.recipe.clone()) {
 451→                        Ok((value, generator_id, recipe)) => {
 452→                            resp.status = "generate".to_string();
 453→                            resp.value = Some(value);
 454→                            resp.generator_id = Some(generator_id);
 455→                            resp.recipe = Some(recipe);
 456→                            resp
 457→                        }
 458→                        Err(e) => {
