 491→    fn send(&mut self, resp: &Response) -> io::Result<()> {
 492→        let data = serde_json::to_string(resp)
 493→            .map_err(io::Error::other)?;
 494→        self.logf(&format!("Sent: {data}"));
 495→        writeln!(self.writer, "{data}")?;
 496→        self.writer.flush()
 497→    }
