 503→
 504→    /// Log at a specific level.
 505→    fn log_at(&mut self, level: FrontendLogLevel, msg: &str) {
 506→        if self.log_level >= level {
 507→            let _ = writeln!(self.log, "[shatter-rust] {msg}");
 508→        }
 509→    }
