  1→//! Execute instrumented Rust code via subprocess compilation.
  2→//!
  3→//! Instruments the target function, generates a `main()` harness that links
  4→//! `shatter_rust_runtime`, compiles to a binary in a temp directory, runs it,
  5→//! and parses the JSON `ExecuteResult` from stdout.
  6→
  7→use std::io;
  8→use std::path::{Path, PathBuf};
  9→use std::process::Command;
 10→use std::time::{Duration, Instant};
 11→
 12→use serde_json::Value;
 13→
 14→use crate::instrument;
 15→
 16→/// Wrap instrumented source in `mod user_code { ... }` with all top-level items
 17→/// made `pub`, so the harness `main()` can call the target function without
 18→/// name collisions (e.g. duplicate `main()` from the original source).
 19→fn wrap_in_module(source: &str) -> Result<String, ExecuteError> {
 20→    use quote::ToTokens;
 21→
 22→    let mut file = syn::parse_file(source)
 23→        .map_err(|e| ExecuteError::InstrumentError(format!("parse error: {e}")))?;
 24→
 25→    for item in &mut file.items {
 26→        match item {
 27→            syn::Item::Fn(f) => f.vis = syn::Visibility::Public(syn::token::Pub::default()),
 28→            syn::Item::Struct(s) => s.vis = syn::Visibility::Public(syn::token::Pub::default()),
 29→            syn::Item::Enum(e) => e.vis = syn::Visibility::Public(syn::token::Pub::default()),
 30→            syn::Item::Type(t) => t.vis = syn::Visibility::Public(syn::token::Pub::default()),
 31→            syn::Item::Const(c) => c.vis = syn::Visibility::Public(syn::token::Pub::default()),
 32→            syn::Item::Static(s) => s.vis = syn::Visibility::Public(syn::token::Pub::default()),
 33→            syn::Item::Trait(t) => t.vis = syn::Visibility::Public(syn::token::Pub::default()),
 34→            syn::Item::Mod(m) => m.vis = syn::Visibility::Public(syn::token::Pub::default()),
 35→            _ => {}
 36→        }
 37→    }
 38→
 39→    let tokens = file.to_token_stream().to_string();
 40→    Ok(format!("#[allow(dead_code)]\nmod user_code {{\n{tokens}\n}}"))
 41→}
 42→
 43→/// Errors from the execute pipeline.
 44→#[derive(Debug)]
 45→pub enum ExecuteError {
 46→    /// Source file not found or unreadable.
 47→    FileError(String),
 48→    /// Instrumentation failed (parse error, etc.).
 49→    InstrumentError(String),
 50→    /// Failed to write temp project files.
 51→    IoError(io::Error),
 52→    /// `cargo build` failed with compiler output.
 53→    CompilationFailed(String),
 54→    /// Binary produced no parseable output.
 55→    OutputParseError(String),
 56→}
 57→
 58→impl std::fmt::Display for ExecuteError {
 59→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 60→        match self {
 61→            Self::FileError(e) => write!(f, "file error: {e}"),
 62→            Self::InstrumentError(e) => write!(f, "instrumentation error: {e}"),
 63→            Self::IoError(e) => write!(f, "I/O error: {e}"),
 64→            Self::CompilationFailed(e) => write!(f, "compilation failed: {e}"),
 65→            Self::OutputParseError(e) => write!(f, "output parse error: {e}"),
 66→        }
 67→    }
 68→}
 69→
 70→impl From<io::Error> for ExecuteError {
 71→    fn from(e: io::Error) -> Self {
 72→        Self::IoError(e)
 73→    }
 74→}
 75→
 76→/// Result of executing an instrumented function. Uses `serde_json::Value`
 77→/// for fields to stay wire-compatible without duplicating runtime types.
 78→#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
 79→pub struct ExecuteResult {
 80→    pub return_value: Option<Value>,
 81→    pub thrown_error: Option<Value>,
 82→    #[serde(default)]
 83→    pub branch_path: Vec<Value>,
 84→    #[serde(default)]
 85→    pub lines_executed: Vec<u32>,
 86→    #[serde(default)]
 87→    pub calls_to_external: Vec<Value>,
 88→    #[serde(default)]
 89→    pub path_constraints: Vec<Value>,
 90→    #[serde(default)]
 91→    pub side_effects: Vec<Value>,
 92→    pub performance: Value,
 93→}
 94→
 95→const DEFAULT_BUILD_TIMEOUT_SECS: u64 = 30;
 96→
 97→/// Locate the shatter-rust-runtime crate by walking up from the shatter-rust binary.
 98→fn find_runtime_crate_path() -> Result<PathBuf, ExecuteError> {
 99→    // Try SHATTER_RUNTIME_PATH env var first (for testing and deployment).
100→    if let Ok(p) = std::env::var("SHATTER_RUNTIME_PATH") {
101→        let path = PathBuf::from(&p);
102→        if path.join("Cargo.toml").exists() {
103→            return Ok(path);
104→        }
105→    }
106→
107→    // Walk up from current exe to find shatter-rust-runtime as a sibling.
108→    if let Ok(exe) = std::env::current_exe() {
109→        let mut dir = exe.parent().map(Path::to_path_buf);
110→        for _ in 0..5 {
111→            if let Some(d) = &dir {
112→                let candidate = d.join("shatter-rust-runtime");
113→                if candidate.join("Cargo.toml").exists() {
114→                    return Ok(candidate);
115→                }
116→                dir = d.parent().map(Path::to_path_buf);
117→            }
118→        }
119→    }
120→
121→    Err(ExecuteError::FileError(
122→        "cannot locate shatter-rust-runtime crate; set SHATTER_RUNTIME_PATH".to_string(),
123→    ))
124→}
125→
126→/// Extracted function signature for harness generation.
127→struct FnSignature {
128→    param_names: Vec<String>,
129→    param_types: Vec<String>,
130→    return_type: Option<String>,
131→}
132→
133→/// Extract parameter info from a Rust source file for a specific function.
134→fn extract_fn_signature(
135→    source: &str,
136→    function_name: &str,
137→) -> Result<FnSignature, ExecuteError> {
138→    use quote::ToTokens;
139→
140→    let file = syn::parse_file(source)
141→        .map_err(|e| ExecuteError::InstrumentError(format!("parse error: {e}")))?;
142→
143→    for item in &file.items {
144→        if let syn::Item::Fn(item_fn) = item
145→            && item_fn.sig.ident == function_name
146→        {
147→            let mut param_names = Vec::new();
148→            let mut param_types = Vec::new();
149→
150→            for arg in &item_fn.sig.inputs {
151→                if let syn::FnArg::Typed(pat_type) = arg {
152→                    let name = pat_type.pat.to_token_stream().to_string();
153→                    let ty = pat_type.ty.to_token_stream().to_string();
154→                    param_names.push(name);
155→                    param_types.push(ty);
156→                }
157→            }
158→
159→            let return_type = match &item_fn.sig.output {
160→                syn::ReturnType::Default => None,
161→                syn::ReturnType::Type(_, ty) => Some(ty.to_token_stream().to_string()),
162→            };
163→
164→            return Ok(FnSignature { param_names, param_types, return_type });
165→        }
166→    }
167→
168→    Err(ExecuteError::InstrumentError(format!(
169→        "function not found: {function_name}"
170→    )))
171→}
172→
173→/// Generate a Cargo.toml for the temp project.
174→fn generate_cargo_toml(runtime_path: &Path) -> String {
175→    let runtime_path_str = runtime_path.display().to_string().replace('\\', "/");
176→    format!(
177→        r#"[package]
178→name = "shatter-exec-temp"
179→version = "0.1.0"
180→edition = "2021"
181→
182→[dependencies]
183→serde = {{ version = "1", features = ["derive"] }}
184→serde_json = "1"
185→shatter-rust-runtime = {{ path = "{runtime_path_str}" }}
186→"#
187→    )
188→}
189→
190→/// Generate the main.rs harness that calls the target function.
191→///
192→/// Wraps instrumented source in `mod user_code` to avoid name collisions
193→/// (e.g. duplicate `fn main()` when the source file has its own `main`).
194→fn generate_harness(
195→    instrumented_source: &str,
196→    function_name: &str,
197→    param_names: &[String],
198→    param_types: &[String],
199→    return_type: Option<&str>,
200→    inputs_json: &str,
201→    mocks_json: &str,
202→) -> Result<String, ExecuteError> {
203→    let module_block = wrap_in_module(instrumented_source)?;
204→    let mut h = String::with_capacity(4096);
205→
206→    h.push_str("use serde_json::Value;\n\n");
207→    h.push_str(&module_block);
208→    h.push_str("\n\nfn main() {\n");
209→
210→    // Parse inputs
211→    h.push_str(&format!(
212→        "    let inputs_json = r#\"{}\"#;\n",
213→        inputs_json
214→    ));
215→    h.push_str(
216→        "    let inputs: Vec<Value> = serde_json::from_str(inputs_json).unwrap_or_default();\n\n",
217→    );
218→
219→    // Parse and register mocks
220→    h.push_str(&format!(
221→        "    let mocks_json = r#\"{}\"#;\n",
222→        mocks_json
223→    ));
224→    h.push_str("    let mocks: Vec<Value> = serde_json::from_str(mocks_json).unwrap_or_default();\n");
225→    h.push_str("    for mock in &mocks {\n");
226→    h.push_str("        if let (Some(symbol), Some(return_values)) = (\n");
227→    h.push_str("            mock.get(\"symbol\").and_then(|s| s.as_str()),\n");
228→    h.push_str("            mock.get(\"return_values\").and_then(|v| v.as_array()),\n");
229→    h.push_str("        ) {\n");
230→    h.push_str(
231→        "            shatter_rust_runtime::register_mock(symbol, return_values.clone());\n",
232→    );
233→    h.push_str("        }\n");
234→    h.push_str("    }\n\n");
235→
236→    // Reset runtime state
237→    h.push_str("    shatter_rust_runtime::reset();\n\n");
238→
239→    // Deserialize each input parameter
240→    for (i, (name, ty)) in param_names.iter().zip(param_types.iter()).enumerate() {
241→        let clean_name = name.strip_prefix("mut ").unwrap_or(name).trim();
242→        h.push_str(&format!(
243→            "    let {clean_name}: {ty} = serde_json::from_value(inputs[{i}].clone()).unwrap_or_default();\n"
244→        ));
245→    }
246→    h.push('\n');
247→
248→    // Build the argument list
249→    let arg_list: Vec<&str> = param_names
250→        .iter()
251→        .map(|n| n.strip_prefix("mut ").unwrap_or(n).trim())
252→        .collect();
253→    let args = arg_list.join(", ");
254→
255→    // Call the function inside catch_unwind, measuring time
256→    h.push_str("    let start = std::time::Instant::now();\n");
257→    h.push_str("    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {\n");
258→    h.push_str(&format!("        user_code::{function_name}({args})\n"));
259→    h.push_str("    }));\n");
260→    h.push_str("    let wall_time_ms = start.elapsed().as_secs_f64() * 1000.0;\n\n");
261→
262→    // Flush runtime results
263→    h.push_str(
264→        "    let runtime_json = shatter_rust_runtime::flush_results();\n",
265→    );
266→    h.push_str(
267→        "    let mut exec_result: Value = serde_json::from_str(&runtime_json).unwrap_or(Value::Object(Default::default()));\n",
268→    );
269→    h.push_str("    let obj = exec_result.as_object_mut().unwrap();\n\n");
270→
271→    // Set return_value or thrown_error
272→    h.push_str("    match result {\n");
273→    if return_type.is_some() {
274→        h.push_str("        Ok(ret_val) => {\n");
275→        h.push_str(
276→            "            obj.insert(\"return_value\".into(), serde_json::to_value(&ret_val).unwrap_or(Value::Null));\n",
277→        );
278→        h.push_str("        }\n");
279→    } else {
280→        h.push_str("        Ok(()) => {\n");
281→        h.push_str("            obj.insert(\"return_value\".into(), Value::Null);\n");
282→        h.push_str("        }\n");
283→    }
284→    h.push_str("        Err(panic_info) => {\n");
285→    h.push_str("            let msg = if let Some(s) = panic_info.downcast_ref::<&str>() {\n");
286→    h.push_str("                s.to_string()\n");
287→    h.push_str("            } else if let Some(s) = panic_info.downcast_ref::<String>() {\n");
288→    h.push_str("                s.clone()\n");
289→    h.push_str("            } else {\n");
290→    h.push_str("                format!(\"{:?}\", panic_info)\n");
291→    h.push_str("            };\n");
292→    h.push_str("            obj.insert(\"thrown_error\".into(), serde_json::json!({\n");
293→    h.push_str("                \"error_type\": \"runtime_error\",\n");
294→    h.push_str("                \"message\": msg,\n");
295→    h.push_str("            }));\n");
296→    h.push_str("        }\n");
297→    h.push_str("    }\n\n");
298→
299→    // Set performance metrics
300→    h.push_str("    obj.insert(\"performance\".into(), serde_json::json!({\n");
301→    h.push_str("        \"wall_time_ms\": wall_time_ms,\n");
302→    h.push_str("        \"cpu_time_us\": 0,\n");
303→    h.push_str("        \"heap_used_bytes\": 0,\n");
304→    h.push_str("        \"heap_allocated_bytes\": 0,\n");
305→    h.push_str("    }));\n\n");
306→
307→    // Ensure side_effects is present
308→    h.push_str("    obj.entry(\"side_effects\").or_insert(serde_json::json!([]));\n\n");
309→
310→    // Print the result JSON to stdout
311→    h.push_str("    println!(\"{}\", serde_json::to_string(&exec_result).unwrap());\n");
312→    h.push_str("}\n");
313→
314→    Ok(h)
315→}
316→
317→/// Execute an instrumented Rust function by compiling and running a temp project.
318→///
319→/// Returns the parsed `ExecuteResult` on success. Compilation and runtime errors
320→/// are reported as `ExecuteError` variants that the handler maps to protocol responses.
321→pub fn execute_function(
322→    file_path: &str,
323→    function_name: &str,
324→    inputs: &[Value],
325→    mocks: &[Value],
326→    timeout_ms: u64,
327→) -> Result<ExecuteResult, ExecuteError> {
328→    let path = Path::new(file_path);
329→    if !path.exists() {
330→        return Err(ExecuteError::FileError(format!(
331→            "file not found: {file_path}"
332→        )));
333→    }
334→
335→    let source = std::fs::read_to_string(path)
336→        .map_err(|e| ExecuteError::FileError(format!("cannot read {file_path}: {e}")))?;
337→
338→    // Extract function signature for harness generation
339→    let sig = extract_fn_signature(&source, function_name)?;
340→
341→    if inputs.len() != sig.param_names.len() {
342→        return Err(ExecuteError::InstrumentError(format!(
343→            "expected {} inputs for {function_name}, got {}",
344→            sig.param_names.len(),
345→            inputs.len()
346→        )));
347→    }
348→
349→    // Instrument the source targeting the specific function
350→    let instr_result = instrument::instrument_source(&source, Some(function_name))
351→        .map_err(|e| ExecuteError::InstrumentError(e.to_string()))?;
352→
353→    // Find the runtime crate
354→    let runtime_path = find_runtime_crate_path()?;
355→
356→    // Serialize inputs and mocks for embedding
357→    let inputs_json = serde_json::to_string(inputs)
358→        .map_err(|e| ExecuteError::InstrumentError(format!("cannot serialize inputs: {e}")))?;
359→    let mocks_json = serde_json::to_string(mocks)
360→        .map_err(|e| ExecuteError::InstrumentError(format!("cannot serialize mocks: {e}")))?;
361→
362→    // Generate the harness
363→    let harness = generate_harness(
364→        &instr_result.source,
365→        function_name,
366→        &sig.param_names,
367→        &sig.param_types,
368→        sig.return_type.as_deref(),
369→        &inputs_json,
370→        &mocks_json,
371→    )?;
372→
373→    // Create temp directory with unique name
374→    let temp_dir = std::env::temp_dir().join(format!(
375→        "shatter-exec-{}-{}",
376→        std::process::id(),
377→        std::time::SystemTime::now()
378→            .duration_since(std::time::UNIX_EPOCH)
379→            .map(|d| d.as_millis())
380→            .unwrap_or(0)
381→    ));
382→    std::fs::create_dir_all(temp_dir.join("src"))?;
383→
384→    // Write project files
385→    let cargo_toml = generate_cargo_toml(&runtime_path);
386→    std::fs::write(temp_dir.join("Cargo.toml"), cargo_toml)?;
387→    std::fs::write(temp_dir.join("src/main.rs"), &harness)?;
388→
389→    // Compile
390→    let build_timeout = Duration::from_secs(DEFAULT_BUILD_TIMEOUT_SECS);
391→    let build_start = Instant::now();
392→    let build_output = Command::new("cargo")
393→        .args(["build", "--release"])
394→        .current_dir(&temp_dir)
395→        .output()
396→        .map_err(|e| ExecuteError::CompilationFailed(format!("failed to run cargo: {e}")))?;
397→
398→    if build_start.elapsed() > build_timeout {
399→        let _ = std::fs::remove_dir_all(&temp_dir);
400→        return Err(ExecuteError::CompilationFailed(
401→            "build timed out".to_string(),
402→        ));
403→    }
404→
405→    if !build_output.status.success() {
406→        let stderr = String::from_utf8_lossy(&build_output.stderr);
407→        let _ = std::fs::remove_dir_all(&temp_dir);
408→        return Err(ExecuteError::CompilationFailed(stderr.into_owned()));
409→    }
410→
411→    // Find the compiled binary
412→    let binary_name = if cfg!(windows) {
413→        "shatter-exec-temp.exe"
414→    } else {
415→        "shatter-exec-temp"
416→    };
417→    let binary_path = temp_dir.join("target/release").join(binary_name);
418→
419→    if !binary_path.exists() {
420→        let _ = std::fs::remove_dir_all(&temp_dir);
421→        return Err(ExecuteError::CompilationFailed(
422→            "compiled binary not found".to_string(),
423→        ));
424→    }
425→
426→    // Run the binary with timeout
427→    let exec_timeout = Duration::from_millis(timeout_ms);
428→    let run_start = Instant::now();
429→    let run_output = Command::new(&binary_path)
430→        .current_dir(&temp_dir)
431→        .output()
432→        .map_err(|e| {
433→            let _ = std::fs::remove_dir_all(&temp_dir);
434→            ExecuteError::OutputParseError(format!("failed to run binary: {e}"))
435→        })?;
436→    let wall_time_ms = run_start.elapsed().as_secs_f64() * 1000.0;
437→
438→    // Clean up temp dir
439→    let _ = std::fs::remove_dir_all(&temp_dir);
440→
441→    // Check for timeout
442→    if run_start.elapsed() > exec_timeout {
443→        return Ok(ExecuteResult {
444→            return_value: None,
445→            thrown_error: Some(serde_json::json!({
446→                "error_type": "timeout",
447→                "message": format!("execution timed out after {}ms", timeout_ms),
448→            })),
449→            branch_path: vec![],
450→            lines_executed: vec![],
451→            calls_to_external: vec![],
452→            path_constraints: vec![],
453→            side_effects: vec![],
454→            performance: serde_json::json!({
455→                "wall_time_ms": wall_time_ms,
456→                "cpu_time_us": 0,
457→                "heap_used_bytes": 0,
458→                "heap_allocated_bytes": 0,
459→            }),
460→        });
461→    }
462→
463→    // Parse stdout
464→    let stdout = String::from_utf8_lossy(&run_output.stdout);
465→    let stderr_str = String::from_utf8_lossy(&run_output.stderr);
466→
467→    // Check for runtime crash (non-zero exit without output)
468→    if !run_output.status.success() && stdout.trim().is_empty() {
469→        return Ok(ExecuteResult {
470→            return_value: None,
471→            thrown_error: Some(serde_json::json!({
472→                "error_type": "runtime_error",
473→                "message": if stderr_str.is_empty() {
474→                    format!("process exited with {}", run_output.status)
475→                } else {
476→                    stderr_str.into_owned()
477→                },
478→            })),
479→            branch_path: vec![],
480→            lines_executed: vec![],
481→            calls_to_external: vec![],
482→            path_constraints: vec![],
483→            side_effects: vec![],
484→            performance: serde_json::json!({
485→                "wall_time_ms": wall_time_ms,
486→                "cpu_time_us": 0,
487→                "heap_used_bytes": 0,
488→                "heap_allocated_bytes": 0,
489→            }),
490→        });
491→    }
492→
493→    // Parse the JSON output from stdout
494→    let result: ExecuteResult = serde_json::from_str(stdout.trim()).map_err(|e| {
495→        ExecuteError::OutputParseError(format!(
496→            "failed to parse execute result: {e}\nstdout: {stdout}\nstderr: {stderr_str}"
497→        ))
498→    })?;
499→
500→    Ok(result)
501→}
