503→#[cfg(test)]
504→mod tests {
505→    use super::*;
506→
507→    #[test]
508→    fn find_runtime_crate_via_env() {
509→        let runtime_path = find_runtime_crate_path();
510→        assert!(
511→            runtime_path.is_ok(),
512→            "should find runtime crate: {:?}",
513→            runtime_path.err()
514→        );
515→    }
516→
517→    #[test]
518→    fn extract_fn_signature_simple() {
519→        let source = "fn classify_number(n: i32) -> &'static str { \"\" }";
520→        let sig = extract_fn_signature(source, "classify_number").unwrap();
521→        assert_eq!(sig.param_names, vec!["n"]);
522→        assert_eq!(sig.param_types, vec!["i32"]);
523→        assert!(sig.return_type.is_some());
524→    }
525→
526→    #[test]
527→    fn extract_fn_signature_multiple_params() {
528→        let source = "fn add(a: i32, b: i32) -> i32 { a + b }";
529→        let sig = extract_fn_signature(source, "add").unwrap();
530→        assert_eq!(sig.param_names, vec!["a", "b"]);
531→        assert_eq!(sig.param_types, vec!["i32", "i32"]);
532→        assert_eq!(sig.return_type.as_deref(), Some("i32"));
533→    }
