538→        let sig = extract_fn_signature(source, "noop").unwrap();
539→        assert!(sig.param_names.is_empty());
540→        assert!(sig.param_types.is_empty());
541→        assert!(sig.return_type.is_none());
542→    }
543→
544→    #[test]
545→    fn extract_fn_signature_not_found() {
546→        let source = "fn other() {}";
547→        let result = extract_fn_signature(source, "missing");
548→        assert!(result.is_err());
549→    }
550→
551→    #[test]
552→    fn generate_cargo_toml_includes_runtime_dep() {
553→        let toml = generate_cargo_toml(Path::new("/home/user/shatter-rust-runtime"));
554→        assert!(toml.contains("shatter-rust-runtime"));
555→        assert!(toml.contains("/home/user/shatter-rust-runtime"));
556→    }
557→
558→    #[test]
559→    fn generate_harness_contains_function_call() {
560→        let harness = generate_harness(
561→            "fn classify_number(n: i32) -> &'static str { \"\" }",
562→            "classify_number",
563→            &["n".to_string()],
564→            &["i32".to_string()],
565→            Some("& 'static str"),
566→            "[42]",
567→            "[]",
568→        )
569→        .unwrap();
570→        assert!(harness.contains("mod user_code"));
571→        assert!(harness.contains("user_code::classify_number(n)"));
572→        assert!(harness.contains("catch_unwind"));
573→        assert!(harness.contains("flush_results"));
574→        assert!(harness.contains("shatter_rust_runtime::reset()"));
575→    }
576→
577→    #[test]
578→    fn generate_harness_void_function() {
579→        let harness = generate_harness(
580→            "fn noop() {}",
581→            "noop",
582→            &[],
583→            &[],
584→            None,
585→            "[]",
586→            "[]",
587→        )
588→        .unwrap();
589→        assert!(harness.contains("user_code::noop()"));
590→        assert!(harness.contains("Ok(())"));
591→    }
592→
593→    /// Reproduction test for str-cfhk: source with `fn main()` must not
594→    /// produce a harness with two top-level `main` definitions.
595→    #[test]
596→    fn generate_harness_no_duplicate_main() {
597→        let source = r#"
598→fn classify_number(n: i32) -> &'static str {
599→    if n < 0 { "negative" } else { "non-negative" }
600→}
601→
602→fn main() {
603→    println!("{}", classify_number(42));
604→}
605→"#;
606→        let harness = generate_harness(
607→            source,
608→            "classify_number",
609→            &["n".to_string()],
610→            &["i32".to_string()],
611→            Some("& 'static str"),
612→            "[42]",
613→            "[]",
614→        )
615→        .unwrap();
616→
617→        // The user's main() should be inside mod user_code, not at top level
618→        assert!(harness.contains("mod user_code"));
619→        assert!(harness.contains("user_code::classify_number(n)"));
620→
621→        // Count top-level `fn main()` — should be exactly 1 (the harness's)
622→        let top_level_mains = harness
623→            .lines()
624→            .filter(|line| {
625→                let trimmed = line.trim();
626→                // Top-level main: starts at column 0 (not indented inside mod)
627→                !line.starts_with(' ') && !line.starts_with('\t')
628→                    && (trimmed == "fn main() {" || trimmed.starts_with("fn main()"))
629→            })
630→            .count();
631→        assert_eq!(
632→            top_level_mains, 1,
633→            "expected exactly 1 top-level fn main(), found {top_level_mains}\n\nharness:\n{harness}"
634→        );
635→    }
