  6→/// Caches loaded WASM plugins by file path to avoid reloading on repeated generate calls.
  7→pub struct WasmCache {
  8→    plugins: HashMap<String, Plugin>,
  9→}
 10→
 11→impl WasmCache {
 12→    pub fn new() -> Self {
 13→        Self {
 14→            plugins: HashMap::new(),
 15→        }
 16→    }
 17→
 18→    /// Invoke a WASM generator plugin.
 19→    ///
 20→    /// Loads the plugin from `wasm_path` (caching it for future calls), then calls
 21→    /// `func_name` with the JSON-serialized `recipe` (or an empty string if absent).
 22→    /// The plugin must return JSON: `{"id": "...", "value": ..., "recipe": ...}`.
 23→    /// Returns `(value, generator_id, optional_recipe)`.
 24→    pub fn generate(
 25→        &mut self,
 26→        wasm_path: &Path,
 27→        func_name: &str,
 28→        recipe: Option<&serde_json::Value>,
 29→    ) -> Result<(serde_json::Value, String, Option<serde_json::Value>), String> {
 30→        let key = wasm_path
 31→            .to_str()
 32→            .ok_or_else(|| format!("non-UTF-8 WASM path: {}", wasm_path.display()))?
 33→            .to_string();
 34→
 35→        if !self.plugins.contains_key(&key) {
 36→            let plugin = self.load_plugin(wasm_path)?;
 37→            self.plugins.insert(key.clone(), plugin);
 38→        }
 39→
 40→        let plugin = self
 41→            .plugins
 42→            .get_mut(&key)
 43→            .expect("just inserted above");
 44→
 45→        let input = match recipe {
 46→            Some(r) => serde_json::to_string(r).map_err(|e| format!("serialize recipe: {e}"))?,
 47→            None => String::new(),
 48→        };
 49→
 50→        let output = plugin
 51→            .call::<&str, &str>(func_name, &input)
 52→            .map_err(|e| format!("WASM call failed: {e}"))?;
 53→
 54→        let parsed: serde_json::Value =
 55→            serde_json::from_str(output).map_err(|e| format!("invalid JSON from WASM plugin: {e}"))?;
 56→
 57→        let id = parsed
 58→            .get("id")
 59→            .and_then(|v| v.as_str())
 60→            .ok_or_else(|| "WASM output missing \"id\" string field".to_string())?
 61→            .to_string();
 62→
 63→        let value = parsed
 64→            .get("value")
 65→            .cloned()
 66→            .ok_or_else(|| "WASM output missing \"value\" field".to_string())?;
 67→
 68→        let new_recipe = parsed.get("recipe").cloned();
 69→
 70→        Ok((value, id, new_recipe))
 71→    }
 72→
 73→    fn load_plugin(&self, wasm_path: &Path) -> Result<Plugin, String> {
 74→        if !wasm_path.exists() {
 75→            return Err(format!("WASM file not found: {}", wasm_path.display()));
 76→        }
 77→
 78→        let wasm = Wasm::file(wasm_path);
 79→        let manifest = Manifest::new([wasm]);
 80→        Plugin::new(&manifest, [], true).map_err(|e| format!("failed to load WASM plugin: {e}"))
 81→    }
 82→}
 83→
 84→#[cfg(test)]
 85→mod tests {
 86→    use super::*;
 87→    use std::path::PathBuf;
 88→
 89→    #[test]
 90→    fn missing_wasm_file_returns_error() {
 91→        let mut cache = WasmCache::new();
 92→        let path = PathBuf::from("/nonexistent/path/gen.wasm");
 93→        let result = cache.generate(&path, "generate", None);
 94→        assert!(result.is_err());
 95→        let err = result.unwrap_err();
 96→        assert!(
 97→            err.contains("not found"),
 98→            "expected 'not found' in error, got: {err}"
 99→        );
100→    }
101→
102→    #[test]
103→    fn cache_retains_plugin_entry() {
104→        let mut cache = WasmCache::new();
105→        // First call fails because the file doesn't exist, but we can verify
106→        // that a second call to a *different* missing file produces distinct errors.
107→        let path_a = PathBuf::from("/tmp/shatter-wasm-test-a.wasm");
108→        let path_b = PathBuf::from("/tmp/shatter-wasm-test-b.wasm");
109→        let err_a = cache.generate(&path_a, "gen", None).unwrap_err();
110→        let err_b = cache.generate(&path_b, "gen", None).unwrap_err();
